/* Ensure professional kerning is applied for refined UI text */
h1, h2, .display-heading {
  font-kerning: normal; /* Activates font-specific kerning data, if available */
  text-rendering: optimizeLegibility; /* Hints browser to prioritize readability, can impact performance */
}

/* Example of disabling kerning for specific elements, e.g., monospaced code blocks */
.code-block {
  font-kerning: none;
  letter-spacing: normal; /* Override any inherited letter-spacing if needed */
}
